module RefModule (
    input wire clk,
    input wire rst,
    output reg [4-1:1-1] count
);

    always @(posedge clk or posedge rst) begin
        if (rst) begin
            count <= 4'b0001;
        end else begin
            count <= {count[2:0], count[3]};
        end
    end

endmodule
